import React, { Component } from "react";
import defaultImg from "./image/default.jpg";
import "./index.css"; // make sure to add the CSS below

class Application extends Component {
  constructor(props) {
    super(props);

    const saveProfile = JSON.parse(localStorage.getItem("userProfile")) || {};
    const saveImg = localStorage.getItem("profileImg");

    this.state = {
      firstName: saveProfile.firstName || "",
      lastName: saveProfile.lastName || "",
      email: saveProfile.email || "",
      regDate: saveProfile.regDate || "",
      gender: saveProfile.gender || "",
      weight: saveProfile.weight || "",
      height: saveProfile.height || "",
      profileImg: saveImg || defaultImg,
    };

    this.fileInputRef = React.createRef();
  }

  handleProfileChange = (event) => {
    const file = event.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        localStorage.setItem("profileImg", e.target.result);
        this.setState({ profileImg: e.target.result });
      };
      reader.readAsDataURL(file);
    }
  };

  handleChange = (event) => {
    const { name, value } = event.target;
    this.setState({ [name]: value });
  };

  render() {
    const { firstName, lastName, email, regDate, gender, weight, height, profileImg } = this.state;

    return (
      <div className="profile-container">
        {/* Header */}
        <div className="header">
          <h3>Edit Profile</h3>
        </div>

        {/* Profile Picture */}
        <div className="profile-pic-container">
          <img src={profileImg} alt="Profile" className="profile-pic" />
          <label className="camera-icon" onClick={() => this.fileInputRef.current.click()}>
            📷
          </label>
          <input
            type="file"
            accept="image/*"
            ref={this.fileInputRef}
            style={{ display: "none" }}
            onChange={this.handleProfileChange}
          />
        </div>

        {/* Basic Info */}
        <div className="info-card">
          <div className="info-row">
            <span className="label">Name</span>
            <span className="value">{firstName || lastName ? `${firstName} ${lastName}` : "Not set"}</span>
          </div>
          <div className="info-row">
            <span className="label">Dropl</span>
            <span className="value">Explore Benefits</span>
          </div>
        </div>

        {/* Private Information */}
        <div className="section-title">Private Information</div>
        <div className="info-card">
          <div className="info-row">
            <span className="label">Email</span>
            <span className="value">{email || "Not set"}</span>
          </div>
          <div className="info-row">
            <span className="label">Birthdate</span>
            <span className="value">{regDate || "Not set"}</span>
          </div>
          <div className="info-row">
            <span className="label">Gender</span>
            <span className="value">{gender || "Not set"}</span>
          </div>
          <div className="info-row">
            <span className="label">Weight</span>
            <span className="value">{weight ? `${weight} kg` : "Not set"}</span>
          </div>
          <div className="info-row">
            <span className="label">Height</span>
            <span className="value">{height || "Not set"}</span>
          </div>
        </div>
      </div>
    );
  }
}

export default Application;
